var threeSumClosest = function(nums, target) {
    nums = nums.slice().sort((a, b) => a - b);
    const n = nums.length;
    let best = nums[0] + nums[1] + nums[2];
    for (let i = 0; i < n - 2; i++) {
        let l = i + 1, r = n - 1;
        while (l < r) {
            const s = nums[i] + nums[l] + nums[r];
            if (Math.abs(s - target) < Math.abs(best - target)) best = s;
            if (s < target) l++;
            else if (s > target) r--;
            else return s;
        }
    }
    return best;
};
